// Secure transaction handling and data encryption
extension Account {
    func encrypt(privateKey: String) -> String {
        let data = try! JSONEncoder().encode(self)
        let encryptedData = try! AES.encrypt(data, key: privateKey.data(using: .utf8)!)
        return encryptedData.base64EncodedString()
    }

    func decrypt(privateKey: String) -> Account? {
        guard let encryptedData = Data(base64Encoded: self.id) else { return nil }
        let decryptedData = try! AES.decrypt(encryptedData, key: privateKey.data(using: .utf8)!)
        return try! JSONDecoder().decode(Account.self, from: decryptedData)
    }
